#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X;
        scanf("%lld", &X);
        long long discount1 = X / 10; // 10% discount
        long long discount2 = 100;    // flat discount
        long long ans = discount1 > discount2 ? discount1 : discount2;
        printf("%lld\n", ans);
    }
    return 0;
}

